// ambil semua data di google sheet
let rows = $input.all().map(i => i.json);

// ambil bulan sebelumnya
const now = new Date();

let bln = now.getMonth() - 1;
let thn = now.getFullYear();

// Jika Januari maka kembali ke Desember tahun lalu
if (bln < 0) {
  bln = 11;
  thn -= 1;
}

// MODE TESTING
bln = 4;   // Mei
thn = 2025;

  // Filter bulan
rows = rows.filter(r => {
  const d = new Date(r.Tanggal);

  // skip tanggal invalid
  if (isNaN(d)) return false;

  return (
    d.getMonth() === bln &&
    d.getFullYear() === thn
  );
});

// format bulan dan tahun
const bulan = new Date().toLocaleDateString('id-ID', {
  month: 'long', year: 'numeric'
});

// format rupiah
const rp = n =>
  'Rp ' + Number(n).toLocaleString('id-ID');

// TOTAL
let totalIn = 0;
let totalOut = 0;
const divisiOut = {};

// loop transaksi
for (const r of rows) {

  const n = parseFloat(
    String(r.Nominal)
      .replace(/[^0-9.]/g, '')
  ) || 0;

  r._nominal = n;

  // pemasukan
  if (r.Jenis === 'Pemasukan') {
    totalIn += n;
  }

  // pengeluaran
  else {
    totalOut += n;

    const div = r.Divisi || 'Tidak ada divisi';

    divisiOut[div] =
      (divisiOut[div] || 0) + n;
  }
}

// SALDO
const saldo = totalIn - totalOut;

// HEADER TABEL
const header =
`| Tanggal | Divisi | Keterangan | Jenis | Nominal |
|---------|--------|------------|-------|---------|`;

// ISI TABEL
const dataRows = rows.map(r =>
  `| ${r.Tanggal || '-'} | ${r.Divisi || '-'} | 
  ${r.Keterangan || '-'} | ${r.Jenis || '-'} | 
  ${rp(r._nominal)} |`
).join('\n');

// URUTAN DIVISI
const divisiSorted = Object.entries(divisiOut)
  .sort((a, b) => b[1] - a[1]);

// TABEL DIVISI
const divisiTable =
`| Divisi | Total Pengeluaran | % dari Total |
|--------|------------------|--------------|
` + divisiSorted.map(([div, n]) =>

  `| ${div} | ${rp(n)} | ${
    totalOut > 0
      ? Math.round(n / totalOut * 100)
      : 0
  }% |`

).join('\n');

// FINAL MARKDOWN
const tabelMarkdown = `

## Data Cashflow ${bulan}

### Transaksi Detail

${header}
${dataRows}

### Ringkasan per Divisi (Pengeluaran)

${divisiTable}

### Ringkasan Akhir

- **Total Pemasukan:** ${rp(totalIn)}
- **Total Pengeluaran:** ${rp(totalOut)}
- **Saldo Bersih:** ${rp(saldo)}
- **Jumlah transaksi:** ${rows.length} baris

`.trim();

// OUTPUT JSON
return [{
  json: {
    bulan,
    tabelMarkdown,
    totalPemasukan: totalIn,
    totalPengeluaran: totalOut,
    saldo,
    divisiRanking: divisiSorted,
  }
}];

